SELECT sed.state_name, SUM(sed.net_jobs_displaced) AS TotalJobsDisplaced
FROM state_employment_displacement sed
GROUP BY sed.state_name;

SELECT *
FROM state_employment_displacement
ORDER BY state_employment DESC;

SELECT COUNT(*)
FROM state_employment
WHERE employment_year = 2020 AND total_employment > 800000 AND unemployment_rate < 5;

SELECT state_name, year
FROM state_employment_displacement
LIMIT 10;

SELECT state_name, unemployment_rate
FROM state_employment
ORDER BY unemployment_rate DESC;

SELECT state_name, SUM(net_jobs_displaced) AS total_displaced_jobs 
FROM state_employment_displacement 
WHERE state_name = 'YourStateName';

SELECT state_name 
FROM state_employment 
WHERE total_employment > 80000000;

SELECT state_name, total_employment
FROM state_employment
WHERE total_employment = (
    SELECT MAX(total_employment)
    FROM state_employment
);

SELECT state_name, net_jobs_displaced 
FROM state_employment_displacement
ORDER BY net_jobs_displaced DESC;

SELECT COUNT(*)
FROM state_employment
WHERE employment_year = 2019 AND total_employment > (SELECT AVG(total_employment) FROM state_employment WHERE employment_year = 2019);

SELECT COUNT(*)
FROM affected_jobs
WHERE state_id = 1 AND year = 2023;

SELECT se.state_name, se.total_employment, sed.total_impact_score
FROM state_employment se
JOIN state_employment_displacement sed ON se.state_name = sed.state_name;
